@@ -128,6 +148,13 @@ func (d *Daemon) Stop() error {

 	d.running = false

+	// Shutdown HTTP server if running
+	if d.httpServer != nil {
+		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
+		defer cancel()
+		d.httpServer.Shutdown(ctx)
+	}
+
 	if d.grpcServer != nil {
 		d.grpcServer.GracefulStop()
 	}
